            int c1 = (x != 127);
            int c2 = (add <= y);
            int expr = c1 && c2;
            int expected = (x < y);
            if (expr != expected) s_sle_fails++;

            int c1_or = (x == 127);
            int c2_or = (add > y);
            int expr_or = c1_or || c2_or;
            int expected_or = (x >= y);
            if (expr_or != expected_or) s_sgt_fails++;

            uint8_t ux = ix, uy = iy;
            uint8_t uadd = ux + 1;
            int uc1 = (ux != 255);
            int uc2 = (uadd <= uy);
            if ((uc1 && uc2) != (ux < uy)) u_ule_fails++;

            int uc1_or = (ux == 255);
            int uc2_or = (uadd > uy);
            if ((uc1_or || uc2_or) != (ux >= uy)) u_ugt_fails++;
        }
    }
    printf("Signed SLE fails: %d
", s_sle_fails);
    printf("Signed SGT fails: %d
", s_sgt_fails);
    printf("Unsigned ULE fails: %d
", u_ule_fails);
    printf("Unsigned UGT fails: %d
", u_ugt_fails);
}

int main() { check(); return 0; }
